// Default attachments per weapon index (0=ARC-15, 4=SRX-50)
function defaultAttachments(){
  return {
    0: { scope:'none', mag:'standard', grip:'none', ownedScopes:['none'], ownedMags:['standard'], ownedGrips:['none'] },
    4: { scope:'none', mag:'standard', grip:'none', ownedScopes:['none'], ownedMags:['standard'], ownedGrips:['none'] },
  };
}

function getAttachStats(wi){
  const att = G.attachments[wi];
  if(!att) return { adsMult:1.0, zoomFov:56, magMult:1.0, relMult:1.0, recoilMult:1.0, adsSpdMult:1.0 };
  const sc = ATTACHMENTS.scope.find(a=>a.id===att.scope)||ATTACHMENTS.scope[0];
  const mg = ATTACHMENTS.mag.find(a=>a.id===att.mag)||ATTACHMENTS.mag[0];
  const gr = ATTACHMENTS.grip.find(a=>a.id===att.grip)||ATTACHMENTS.grip[0];
  return { adsMult:sc.adsMult, zoomFov:sc.zoomFov, magMult:mg.magMult, relMult:mg.relMult, recoilMult:gr.recoilMult, adsSpdMult:gr.adsSpdMult };
}

function getEffectiveMag(wi){
  const base = WP[wi].mag;
  const att = getAttachStats(wi);
  return Math.round(base * att.magMult);
}

