function applySettings(){
  S.sens       = parseInt(document.getElementById('s-sens').value)/5000;
  S.adsSens    = parseInt(document.getElementById('s-adssens').value)/10;
  S.fov        = parseInt(document.getElementById('s-fov').value);
  S.xhColor    = document.getElementById('s-xhcol').value;
  S.xhStyle    = xhStyleCurrent;
  S.recoilMult = parseInt(document.getElementById('s-recoil').value)/10;
  S.recoilRecov= parseFloat(document.getElementById('s-recov').value);
  S.hsMult     = parseInt(document.getElementById('s-hs').value)/10;
  S.kickStrength=parseInt(document.getElementById('s-kick').value)/10;
  S.kickRecov  = parseInt(document.getElementById('s-kickrecov').value);
  S.penEnabled = penEnabled;
  S.leanEnabled= leanEnabled;
  S.leanStrength=(parseInt(document.getElementById('s-leanstr').value)/10)*0.6;
  S.leanSpeed  = parseInt(document.getElementById('s-leanspd').value);
  S.armorStart = parseInt(document.getElementById('s-armor').value);
  S.armorAbsorb= parseInt(document.getElementById('s-armorabsorb').value)/100;
  S.grenRadius = parseInt(document.getElementById('s-gren').value)/10;
  S.startMoney = parseInt(document.getElementById('s-money').value);
  S.killReward = parseInt(document.getElementById('s-kreward').value);
  S.winReward  = parseInt(document.getElementById('s-wreward').value);
  S.aiK        = parseInt(document.getElementById('s-ai').value)/100;
  let xhEl=document.getElementById('xh-dyn');
  if(!xhEl){xhEl=document.createElement('style');xhEl.id='xh-dyn';document.head.appendChild(xhEl);}
  const c=S.xhColor;
  if(S.xhStyle==='none') xhEl.textContent=`#xh{opacity:0!important}`;
  else if(S.xhStyle==='dot') xhEl.textContent=`#xh{opacity:1!important}#xh::before{width:6px!important;height:6px!important;left:7px!important;top:7px!important;background:${c}!important}#xh::after{display:none!important}`;
  else xhEl.textContent=`#xh::before{background:${c}!important}#xh::after{background:${c}!important}`;
  if(cam&&!G.ads){cam.fov=S.fov;cam.updateProjectionMatrix();}
}

