// ══════════════════════════════════════════════════════
//  WALL COLLISION SYSTEM
// ══════════════════════════════════════════════════════
const wallBoxes = [];

function box(w,h,d,x,y,z,col, matType='wood', noCollide=false){

  const roughMap={floor:.9,concrete:.85,wood:.92,metal:.45,thin:.75,sand:.95};
  const metalMap={floor:.0,concrete:.0,wood:.0,metal:.5,thin:.1,sand:.0};
  const rgh=roughMap[matType]||.85, mtt=metalMap[matType]||.0;
  const m=new THREE.Mesh(new THREE.BoxGeometry(w,h,d),
    (matType==='metal')?new THREE.MeshStandardMaterial({color:col,roughness:0.45,metalness:0.55}):new THREE.MeshLambertMaterial({color:col}));
  m.position.set(x,y,z); m.receiveShadow=true; m.castShadow=(matType==='metal'||matType==='floor');
  const mat=MATERIALS[matType]||MATERIALS.wood;
  m.userData.isWall=true; m.userData.matType=matType;
  m.userData.matLabel=mat.label; m.userData.thickness=mat.thickness; m.userData.resistance=mat.resistance;
  sc.add(m);
  if(!noCollide && matType!=='floor'){
    const bb=new THREE.Box3().setFromObject(m);
    wallBoxes.push(bb);
  }
  return m;
}

function resolveWallCollisions(){
  const r=0.38;
  const eyeH = G.keys.KeyC ? 1.1 : 1.7;
  const STEP_H = 0.85;
  const px=cam.position.x, py=cam.position.y, pz=cam.position.z;
  for(const wb of wallBoxes){
    if(px+r<=wb.min.x||px-r>=wb.max.x) continue;
    if(pz+r<=wb.min.z||pz-r>=wb.max.z) continue;
    if(py+0.1<=wb.min.y||py-eyeH>=wb.max.y) continue;

    const boxTop = wb.max.y;
    const playerFeet = cam.position.y - eyeH;
    if(boxTop <= playerFeet + STEP_H && boxTop > playerFeet - 0.05){

      cam.position.y = boxTop + eyeH;
      G.vel.y = Math.max(0, G.vel.y);
      G.onGround = true;
      continue; // don't push sideways; let player walk onto surface
    }
    const dxL=(px+r)-wb.min.x, dxR=wb.max.x-(px-r);
    const dzL=(pz+r)-wb.min.z, dzR=wb.max.z-(pz-r);
    const mn=Math.min(dxL,dxR,dzL,dzR);
    if(mn===dxL) cam.position.x=wb.min.x-r;
    else if(mn===dxR) cam.position.x=wb.max.x+r;
    else if(mn===dzL) cam.position.z=wb.min.z-r;
    else cam.position.z=wb.max.z+r;
  }
}

