//  MAP BUILDERS
// ══════════════════════════════════════════════════════
function clearMap(){
  const toRemove=sc.children.filter(c=>c!==cam);
  toRemove.forEach(c=>sc.remove(c));
  wallBoxes.length=0;
}

function buildMap(id){
  clearMap();
  const md=MAPS_DEF[id];
  sc.fog=new THREE.FogExp2(md.fogCol, md.fog);
  sc.background=new THREE.Color(md.fogCol);
  if(id===0) buildMapBreech();
  else if(id===1) buildMapOutpost();
  else if(id===2) buildMapDistrict();
  else if(id===3) buildMapBunker();
  else buildMapGlacier();
  lights(id);
}

