  [[-10,.6,-5,8,.6,.5],[10,.6,5,8,.6,.5],[0,.6,-12,.5,.6,10],[0,.6,12,.5,.6,10],
   [-18,.6,0,6,.6,.5],[18,.6,0,6,.6,.5]].forEach(([x,y,z,w,h,d])=>box(w,h,d,x,y,z,0x9aa8b0,'concrete'));

