// ─── LIGHTS ──────────────────────────────────────────
const flickerLights=[];
function addShadowLight(col,intensity,px,py,pz,near=0.5,far=120,size=40){
  const l=new THREE.DirectionalLight(col,intensity);
  l.position.set(px,py,pz); l.castShadow=true;
  l.shadow.mapSize.width=1024; l.shadow.mapSize.height=1024;
  l.shadow.camera.near=near; l.shadow.camera.far=far;
  l.shadow.camera.left=-size; l.shadow.camera.right=size;
  l.shadow.camera.top=size; l.shadow.camera.bottom=-size;
  l.shadow.bias=-0.0008; l.shadow.radius=3;
  sc.add(l); return l;
}
function lights(mapId){
  flickerLights.length=0;

  if(mapId===0){

    sc.add(new THREE.HemisphereLight(0x1a1208,0x050200,0.55));
    addShadowLight(0xffa060,0.9, 10,16,6, 0.5,120,38);
    addShadowLight(0x4466bb,0.25,-14,10,-8,0.5,80,30);

    const lampPos=[[-14,6.8,-10],[14,6.8,-10],[-14,6.8,10],[14,6.8,10],[0,6.8,0]];
    lampPos.forEach(([x,y,z],i)=>{
      const pl=new THREE.PointLight(0xff7722,3.2,18); pl.position.set(x,y,z); sc.add(pl);
      flickerLights.push({l:pl,base:3.2,timer:Math.random()*2,phase:Math.random()*Math.PI*2});

      const bulb=new THREE.Mesh(new THREE.SphereGeometry(.18,8,5),
        new THREE.MeshStandardMaterial({color:0xff9944,emissive:new THREE.Color(0xff7700),emissiveIntensity:2,roughness:.2}));
      bulb.position.set(x,y+.05,z); sc.add(bulb);

      const cage=new THREE.Mesh(new THREE.TorusGeometry(.22,.025,5,10),
        new THREE.MeshStandardMaterial({color:0x333333,metalness:.8,roughness:.3}));
      cage.position.set(x,y-.08,z); cage.rotation.x=Math.PI/2; sc.add(cage);
    });

    [[-30,5,0],[30,5,0]].forEach(([x,y,z])=>{
      const bl=new THREE.PointLight(0x2244aa,2.0,20); bl.position.set(x,y,z); sc.add(bl);
      flickerLights.push({l:bl,base:2.0,timer:Math.random()*3,fast:true});
      const bulb=new THREE.Mesh(new THREE.SphereGeometry(.12,6,4),
        new THREE.MeshStandardMaterial({color:0x88aaff,emissive:new THREE.Color(0x3355cc),emissiveIntensity:1.5,roughness:.1}));
      bulb.position.set(x,y,z); sc.add(bulb);
    });

    const red=new THREE.PointLight(0xff1100,2.0,12); red.position.set(0,7.8,0); sc.add(red);
    flickerLights.push({l:red,base:2.0,timer:0,beacon:true,beaconT:0});

    sc.add(new THREE.AmbientLight(0x110802,0.4));

  } else if(mapId===1){

    sc.add(new THREE.HemisphereLight(0x9bb4d4,0x6b4e1a,0.75));
    addShadowLight(0xfff0c0,1.6, 18,20,8, 0.5,140,50);
    addShadowLight(0xaaccff,0.35,-12,8,-6,0.5,80,40);

    const sunGlow=new THREE.PointLight(0xffd080,2.2,40); sunGlow.position.set(18,22,8); sc.add(sunGlow);

    sc.add(new THREE.AmbientLight(0x3a2208,0.35));

    const shadow=new THREE.PointLight(0x3355aa,0.6,60); shadow.position.set(0,0.5,0); sc.add(shadow);

    [[-24,3,0],[24,3,0]].forEach(([x,y,z])=>{
      const shaft=new THREE.PointLight(0xffe0a0,1.2,14); shaft.position.set(x,y,z); sc.add(shaft);
    });

  } else if(mapId===3){

    sc.add(new THREE.HemisphereLight(0x100804,0x050200,0.4));
    addShadowLight(0xff5500,0.6,0,8,0,0.5,60,25);

    const redPts=[[-16,5.2,-16],[16,5.2,-16],[-16,5.2,0],[16,5.2,0],[-16,5.2,16],[16,5.2,16]];
    redPts.forEach(([x,y,z],i)=>{
      const el=new THREE.PointLight(0xff2200,2.8,10); el.position.set(x,y,z); sc.add(el);
      flickerLights.push({l:el,base:2.8,timer:Math.random()*2,phase:Math.random()*Math.PI*2,fast:true});
    });

    [[-18,1.5,-14],[-18,1.5,14],[18,1.5,-14],[18,1.5,14]].forEach(([x,y,z])=>{
      const al=new THREE.PointLight(0x00aa00,1.5,8); al.position.set(x,y,z); sc.add(al);
    });
    sc.add(new THREE.AmbientLight(0x0a0402,0.5));
  } else if(mapId===4){

    sc.add(new THREE.HemisphereLight(0xb8d8f0,0x7090a8,0.9));
    addShadowLight(0xd0e8ff,1.4,-10,16,-8,0.5,160,60);
    addShadowLight(0x88aacc,0.4,8,10,6,0.5,100,40);
    sc.add(new THREE.AmbientLight(0x5080a0,0.6));
    sc.fog=new THREE.FogExp2(0x8aa0b0,0.022);
  } else {

    sc.add(new THREE.HemisphereLight(0x0a0820,0x050310,0.35));
    addShadowLight(0x8899cc,0.3, -8,14,-10, 0.5,100,35);

    [[-18,5,-10],[18,5,10],[-18,5,10],[18,5,-10]].forEach(([x,y,z])=>{
      const sl=new THREE.PointLight(0xffcc55,2.5,20); sl.position.set(x,y,z); sl.castShadow=true; sc.add(sl);
      const bulb=new THREE.Mesh(new THREE.SphereGeometry(.14,6,4),
        new THREE.MeshStandardMaterial({color:0xffee88,emissive:new THREE.Color(0xffdd66),emissiveIntensity:2,roughness:.1}));
      bulb.position.set(x,y+.5,z); sc.add(bulb);

      const coneM=new THREE.Mesh(new THREE.ConeGeometry(.8,2.5,8,1,true),
        new THREE.MeshBasicMaterial({color:0xffee00,transparent:true,opacity:.04,side:THREE.DoubleSide}));
      coneM.position.set(x,y-1.5,z); coneM.rotation.x=Math.PI; sc.add(coneM);
    });

    const neons=[
      {pos:[-8,4,-10],col:0x00ffee,base:3.0},{pos:[8,4,10],col:0xff00aa,base:3.0},
      {pos:[-20,3.5,-14],col:0xff4400,base:2.2},{pos:[20,3.5,14],col:0x0088ff,base:2.2},
    ];
    neons.forEach(({pos:[x,y,z],col,base})=>{
      const nl=new THREE.PointLight(col,base,18); nl.position.set(x,y,z); sc.add(nl);
      flickerLights.push({l:nl,base,timer:Math.random()*3,fast:true});

      const tube=new THREE.Mesh(new THREE.BoxGeometry(.8,.08,.06),
        new THREE.MeshStandardMaterial({color:col,emissive:new THREE.Color(col),emissiveIntensity:2.5,roughness:.1}));
      tube.position.set(x,y+.3,z); sc.add(tube);
      const tube2=new THREE.Mesh(new THREE.BoxGeometry(.08,.5,.06),
        new THREE.MeshStandardMaterial({color:col,emissive:new THREE.Color(col),emissiveIntensity:2.5,roughness:.1}));
      tube2.position.set(x-.36,y+.05,z); sc.add(tube2);
    });

    sc.add(new THREE.PointLight(0x550088,1.2,30).translateY(5));

    sc.add(new THREE.PointLight(0xff2200,0.8,22).translateX(0).translateY(4));
    sc.add(new THREE.AmbientLight(0x060810,0.6));
  }
}
// Flicker update (called each frame)
function updFlicker(dt){
  flickerLights.forEach(f=>{
    if(f.beacon){

      f.beaconT=(f.beaconT||0)+dt;
      f.l.intensity=f.base*(0.5+0.5*Math.sin(f.beaconT*4));
      return;
    }
    f.timer-=dt;
    if(f.timer<=0){
      const jitter=f.fast?(Math.random()<.15?0:1):(Math.random()<.04?0.3+Math.random()*0.4:1);
      f.l.intensity=f.base*jitter*(0.85+Math.random()*.3);
      f.timer=f.fast?0.04+Math.random()*.08:0.08+Math.random()*.22;
    }
  });
}

// ══════════════════════════════════════════════════════
//  REAL WEAPON MODEL — embedded compressed geometry
// ══════════════════════════════════════════════════════
const _WGD = {
  pos: "",
  norm: "",
  uv: "",
  count: 147024
};
const _WBC = "data:image/png;base64,";
const _WRG = "data:image/png;base64,";

let _realWepGeo = null, _realWepMats = {};

async function _decompressF32(b64) {
  const bin = atob(b64);
  const bytes = new Uint8Array(bin.length);
  for(let i=0;i<bin.length;i++) bytes[i]=bin.charCodeAt(i);
  const ds = new DecompressionStream('gzip');
  const w2 = ds.writable.getWriter();
  const r2 = ds.readable.getReader();
  w2.write(bytes); w2.close();
  const chunks = [];
  while(true){const {done,value}=await r2.read();if(done)break;chunks.push(value);}
  const total = chunks.reduce((s,c)=>s+c.byteLength,0);
  const out = new Uint8Array(total);
  let off=0; for(const ch of chunks){out.set(ch,off);off+=ch.byteLength;}
  return new Float32Array(out.buffer);
}

async function _loadRealWepGeo() {
  if(_realWepGeo) return _realWepGeo;
  const [pos,norm,uv] = await Promise.all([
    _decompressF32(_WGD.pos),
    _decompressF32(_WGD.norm),
    _decompressF32(_WGD.uv)
  ]);
  const geo = new THREE.BufferGeometry();
  geo.setAttribute('position', new THREE.BufferAttribute(pos, 3));
  geo.setAttribute('normal', new THREE.BufferAttribute(norm, 3));
  geo.setAttribute('uv', new THREE.BufferAttribute(uv, 2));
  _realWepGeo = geo;
  return geo;
}

function _getRealWepMat(variant) {
  if(_realWepMats[variant]) return _realWepMats[variant];
  const loader = new THREE.TextureLoader();
  const bcTex = loader.load(_WBC);
  bcTex.encoding = THREE.sRGBEncoding;
  const rgTex = loader.load(_WRG);
  const mat = new THREE.MeshStandardMaterial({
    map: bcTex,
    roughnessMap: rgTex,
    roughness: 0.55,
    metalness: 0.85,
    envMapIntensity: 1.2,
  });
  _realWepMats[variant] = mat;
  return mat;
}

// Async: loads real weapon mesh and attaches to cam
async function attachRealWep(group, slot) {
  const geo = await _loadRealWepGeo();
  const mat = _getRealWepMat('black');
  const mesh = new THREE.Mesh(geo, mat);
  const scale = 0.018;
  mesh.scale.set(scale, scale, scale);

  mesh.rotation.set(Math.PI*0.07, -Math.PI/2, 0);
  mesh.rotation.z = 0.03;
  mesh._isRealWep = true;

  group.children.forEach(ch => { if(!ch._isRealWep) ch.visible = false; });
  group.add(mesh);
  // Adjust group position for this model's proportions
  if(slot===1){ group.position.set(.20,-.20,-.40); }
  else if(slot===5){ group.position.set(.18,-.22,-.45); }
}

