function tPause(){
  G.pause=!G.pause;
  document.getElementById("pu").style.display=G.pause?"flex":"none";
  document.body.classList.toggle('paused', G.pause);
  if(!G.pause){document.body.classList.remove('paused');ren.domElement.requestPointerLock();}
}

