// CINEMATIC MENU BACKGROUND
(function(){
  const cv=document.getElementById('ov-bg'); if(!cv)return;
  const ctx=cv.getContext('2d');
  let W,H;
  function resize(){W=cv.width=innerWidth;H=cv.height=innerHeight;}
  resize(); window.addEventListener('resize',resize);

  const pts2=Array.from({length:100},()=>({
    x:Math.random()*W, y:Math.random()*H,
    vx:(Math.random()-.5)*.22, vy:(Math.random()-.5)*.22,
    r:Math.random()*1.4+.3,
    a:Math.random()*.5+.12,
    col:Math.random()<.75?[255,90,0]:[0,160,255],
    pulse:Math.random()*Math.PI*2,
    ps:0.5+Math.random()*1.5,
  }));

  const sparks=[];
  let lastSpark=0;
  function addSpark(){
    const side=Math.random()<.5;
    sparks.push({
      x:side?420+Math.random()*100:Math.random()*420,
      y:Math.random()*H,
      vx:(side?1:-1)*(1+Math.random()*3),
      vy:(Math.random()-.5)*1.5,
      life:1, r:0.6+Math.random()
    });
  }

  const GRID=60;

  function frame(t){
    if(document.getElementById('ov').style.display==='none'){requestAnimationFrame(frame);return;}
    ctx.clearRect(0,0,W,H);

    const bg=ctx.createLinearGradient(0,0,W,H);
    bg.addColorStop(0,'rgba(8,4,0,1)');
    bg.addColorStop(.5,'rgba(2,2,6,1)');
    bg.addColorStop(1,'rgba(0,0,0,1)');
    ctx.fillStyle=bg; ctx.fillRect(0,0,W,H);

    const gOff=(t*.012)%GRID;
    ctx.lineWidth=.5;
    for(let x=420;x<W;x+=GRID){
      ctx.strokeStyle='rgba(0,160,255,0.018)';
      ctx.beginPath();ctx.moveTo(x,0);ctx.lineTo(x,H);ctx.stroke();
    }
    for(let y=-GRID;y<H;y+=GRID){
      const yy=((y+gOff)%H+H)%H;
      ctx.strokeStyle='rgba(0,140,255,0.014)';
      ctx.beginPath();ctx.moveTo(420,yy);ctx.lineTo(W,yy);ctx.stroke();
    }

    for(let x=0;x<420;x+=GRID){
      ctx.strokeStyle='rgba(255,80,0,0.028)';
      ctx.beginPath();ctx.moveTo(x,0);ctx.lineTo(x,H);ctx.stroke();
    }
    for(let y=0;y<H;y+=GRID){
      ctx.strokeStyle='rgba(255,60,0,0.018)';
      ctx.beginPath();ctx.moveTo(0,y);ctx.lineTo(420,y);ctx.stroke();
    }

    [[W*.08,H*.25,W*.3,'rgba(255,60,0,0.07)'],[W*.92,H*.75,W*.28,'rgba(0,100,200,0.06)'],
     [W*.5,H*.5,W*.2,'rgba(255,40,0,0.03)']].forEach(([gx,gy,gr,col])=>{
      const grad=ctx.createRadialGradient(gx,gy,0,gx,gy,gr);
      grad.addColorStop(0,col);grad.addColorStop(1,'transparent');
      ctx.fillStyle=grad;ctx.fillRect(0,0,W,H);
    });

    for(let i=0;i<pts2.length;i++){
      for(let j=i+1;j<pts2.length;j++){
        const dx=pts2[i].x-pts2[j].x, dy=pts2[i].y-pts2[j].y;
        const d=Math.sqrt(dx*dx+dy*dy);
        if(d<110){
          const [r,g,b]=pts2[i].col;
          ctx.strokeStyle=`rgba(${r},${g},${b},${.055*(1-d/110)})`;
          ctx.lineWidth=.5;
          ctx.beginPath();ctx.moveTo(pts2[i].x,pts2[i].y);ctx.lineTo(pts2[j].x,pts2[j].y);ctx.stroke();
        }
      }
    }

    pts2.forEach(p=>{
      p.pulse+=p.ps*.016;
      const pa=p.a*(0.7+0.3*Math.sin(p.pulse));
      const [r,g,b]=p.col;
      ctx.fillStyle=`rgba(${r},${g},${b},${pa})`;
      ctx.beginPath();ctx.arc(p.x,p.y,p.r,0,Math.PI*2);ctx.fill();

      if(pa>0.3){
        const pg=ctx.createRadialGradient(p.x,p.y,0,p.x,p.y,p.r*5);
        pg.addColorStop(0,`rgba(${r},${g},${b},${pa*.15})`);pg.addColorStop(1,'rgba(0,0,0,0)');
        ctx.fillStyle=pg;ctx.beginPath();ctx.arc(p.x,p.y,p.r*5,0,Math.PI*2);ctx.fill();
      }
      p.x+=p.vx; p.y+=p.vy;
      if(p.x<0||p.x>W)p.vx*=-1;
      if(p.y<0||p.y>H)p.vy*=-1;
    });

    if(t-lastSpark>220){addSpark();lastSpark=t;}
    for(let i=sparks.length-1;i>=0;i--){
      const s=sparks[i]; s.life-=.015;
      if(s.life<=0){sparks.splice(i,1);continue;}
      const sg=ctx.createRadialGradient(s.x,s.y,0,s.x,s.y,s.r*6);
      sg.addColorStop(0,`rgba(255,160,30,${s.life*.7})`);sg.addColorStop(1,'rgba(255,60,0,0)');
      ctx.fillStyle=sg;ctx.beginPath();ctx.arc(s.x,s.y,s.r*6,0,Math.PI*2);ctx.fill();
      ctx.fillStyle=`rgba(255,230,150,${s.life})`;
      ctx.beginPath();ctx.arc(s.x,s.y,s.r*s.life,0,Math.PI*2);ctx.fill();
      s.x+=s.vx; s.y+=s.vy; s.vx*=.96; s.vy*=.96;
    }

    const div=ctx.createLinearGradient(0,0,0,H);
    div.addColorStop(0,'rgba(255,106,0,0)');
    div.addColorStop(.2,`rgba(255,106,0,${0.4+0.2*Math.sin(t*.001)})`);
    div.addColorStop(.5,`rgba(255,100,0,${0.7+0.3*Math.sin(t*.0012)})`);
    div.addColorStop(.8,`rgba(255,106,0,${0.4+0.2*Math.sin(t*.0008)})`);
    div.addColorStop(1,'rgba(255,106,0,0)');
    ctx.strokeStyle=div; ctx.lineWidth=1.5;
    ctx.beginPath();ctx.moveTo(420,0);ctx.lineTo(420,H);ctx.stroke();

    const dg=ctx.createLinearGradient(408,0,432,0);
    dg.addColorStop(0,'rgba(255,80,0,0)');
    dg.addColorStop(.5,`rgba(255,80,0,${0.06+0.03*Math.sin(t*.001)})`);
    dg.addColorStop(1,'rgba(255,80,0,0)');
    ctx.fillStyle=dg;ctx.fillRect(408,0,24,H);

    requestAnimationFrame(frame);
  }
  requestAnimationFrame(frame);
})();

// ── Quick action helpers ──────────────────────────────
let prevWi=-1;
function quickMelee(){
  if(!G.run||G.dead||G.pause||G.shopOpen||G.inBuyPhase)return;
  if(G.wi===2){shoot();return;}
  prevWi=G.wi; swW(2);
  shoot();
  setTimeout(()=>{if(G.run&&!G.dead&&prevWi>=0)swW(prevWi);prevWi=-1;},320);
}
function quickGrenade(){
  if(!G.run||G.dead||G.pause||G.shopOpen||G.inBuyPhase)return;
  if(G.ammo[3].c<=0){kf('NO GRENADES','');return;}
  if(G.wi===3){shoot();return;}
  prevWi=G.wi; swW(3);
  shoot();
  setTimeout(()=>{if(G.run&&!G.dead&&prevWi>=0)swW(prevWi);prevWi=-1;},500);
}
