// PLAYER MESH — hierarchical animated tactical soldier
// ══════════════════════════════════════════════════════
const playerMesh=(function(){
  const g=new THREE.Group();
  const suitM  = new THREE.MeshStandardMaterial({color:0x1c2b3a,roughness:.85,metalness:.05});
  const armorM = new THREE.MeshStandardMaterial({color:0x2e3d2a,roughness:.80,metalness:.08});
  const plateM = new THREE.MeshStandardMaterial({color:0x1a2218,roughness:.75,metalness:.12});
  const bootM  = new THREE.MeshStandardMaterial({color:0x0d0d0d,roughness:.90,metalness:.02});
  const helmM  = new THREE.MeshStandardMaterial({color:0x141414,roughness:.70,metalness:.15});
  const visorM = new THREE.MeshStandardMaterial({color:0x0066aa,roughness:.05,metalness:.9,transparent:true,opacity:.65});
  const skinM  = new THREE.MeshStandardMaterial({color:0xc07a50,roughness:.80,metalness:.0});
  const gunM   = new THREE.MeshStandardMaterial({color:0x111111,roughness:.35,metalness:.65});
  const gloveM = new THREE.MeshStandardMaterial({color:0x1a1a1a,roughness:.85,metalness:.05});

  function bx(w,h,d,mat,px,py,pz){ const m=new THREE.Mesh(new THREE.BoxGeometry(w,h,d),mat); m.position.set(px,py,pz); return m; }

  const torsoGrp=new THREE.Group(); torsoGrp.position.set(0,0.97,0);
  const torso = bx(.46,.52,.27,suitM, 0,.22,0);
  const pcF   = bx(.38,.34,.07,armorM,0,.28,.165);
  const pcB   = bx(.38,.28,.06,armorM,0,.22,-.160);
  const molL  = bx(.07,.30,.24,armorM,-.26,.22,0);
  const molR  = bx(.07,.30,.24,armorM, .26,.22,0);
  const cpL   = bx(.10,.16,.07,armorM,-.09,.36,.23);
  const cpR   = bx(.10,.16,.07,armorM, .09,.36,.23);
  const cpC   = bx(.07,.14,.07,armorM, 0,.30,.24);
  const radio = bx(.07,.11,.06,bootM, -.19,.46,.13);
  const hips  = bx(.42,.19,.24,suitM, 0,.0,0);
  const belt  = bx(.44,.06,.26,bootM, 0,-.08,0);
  const bpL   = bx(.09,.13,.09,armorM,-.19,-.07,.14);
  const bpR   = bx(.09,.13,.09,armorM, .19,-.07,.14);
  torsoGrp.add(torso,pcF,pcB,molL,molR,cpL,cpR,cpC,radio,hips,belt,bpL,bpR);

  const headGrp=new THREE.Group(); headGrp.position.set(0,.60,0);
  const neck      = bx(.15,.14,.15,skinM,  0,.07,0);
  const head      = bx(.27,.26,.25,skinM,  0,.22,0);
  const helmShell = bx(.35,.24,.34,helmM,  0,.38,-.01);
  const helmBrimF = bx(.32,.06,.12,helmM,  0,.27,.18);
  const helmNape  = bx(.30,.12,.07,helmM,  0,.28,-.18);
  const visor     = bx(.27,.075,.05,visorM,0,.22,.155);
  const nvgBkt    = bx(.06,.05,.09,gunM,   0,.37,.175);
  const earL      = bx(.045,.15,.17,helmM, -.185,.22,0);
  const earR      = bx(.045,.15,.17,helmM,  .185,.22,0);
  const cbl       = bx(.03,.36,.03,bootM,  -.185,.06,0);
  headGrp.add(neck,head,helmShell,helmBrimF,helmNape,visor,nvgBkt,earL,earR,cbl);
  torsoGrp.add(headGrp);

  const armGrpL=new THREE.Group(); armGrpL.position.set(-.33,.48,0);
  const shoulL  = bx(.19,.15,.24,plateM, 0,.06,0);
  const uaL     = bx(.15,.30,.16,suitM,  0,-.12,0);
  const epL     = bx(.17,.10,.13,plateM, 0,-.24,0);
  const elbowGrpL=new THREE.Group(); elbowGrpL.position.set(0,-.32,0);
  const faL     = bx(.13,.28,.14,suitM,  0,-.14,0);
  const hndL    = bx(.13,.10,.13,gloveM, 0,-.31,.02);
  elbowGrpL.add(faL,hndL); armGrpL.add(shoulL,uaL,epL,elbowGrpL);
  torsoGrp.add(armGrpL);

  const armGrpR=new THREE.Group(); armGrpR.position.set(.33,.48,0);
  const shoulR  = bx(.19,.15,.24,plateM, 0,.06,0);
  const uaR     = bx(.15,.30,.16,suitM,  0,-.12,0);
  const epR     = bx(.17,.10,.13,plateM, 0,-.24,0);
  const elbowGrpR=new THREE.Group(); elbowGrpR.position.set(0,-.32,0);
  const faR     = bx(.13,.28,.14,suitM,  0,-.14,0);
  const hndR    = bx(.13,.10,.13,gloveM, 0,-.31,.02);
  elbowGrpR.add(faR,hndR); armGrpR.add(shoulR,uaR,epR,elbowGrpR);
  torsoGrp.add(armGrpR);

  const wbody = bx(.050,.068,.44,gunM,  .33,.30,-.13);
  const wbrl  = bx(.022,.022,.32,gunM,  .33,.31,-.40);
  const wmag  = bx(.040,.18,.056,gunM,  .33,.12,-.07);
  const wstock= bx(.046,.055,.15,gunM,  .33,.28, .10);
  const wgrip = bx(.030,.092,.050,gloveM,.33,.15,.07);
  const wscope= bx(.018,.018,.08,gunM,  .33,.35,-.15);
  torsoGrp.add(wbody,wbrl,wmag,wstock,wgrip,wscope);

  g.add(torsoGrp);

  const legGrpL=new THREE.Group(); legGrpL.position.set(-.135,.93,0);
  const thigL  = bx(.21,.38,.21,suitM, 0,-.19,0);
  const thpL   = bx(.12,.16,.10,armorM,.10,-.18,.06);
  const kneeGrpL=new THREE.Group(); kneeGrpL.position.set(0,-.38,0);
  const kneeL  = bx(.22,.13,.14,plateM, 0,-.01,.05);
  const shinL  = bx(.17,.35,.17,suitM,  0,-.19,0);
  const shpL   = bx(.09,.12,.05,armorM, -.09,-.16,.10);
  const ankleGrpL=new THREE.Group(); ankleGrpL.position.set(0,-.35,0);
  const bootL  = bx(.21,.15,.28,bootM,  0,-.07,.025);
  ankleGrpL.add(bootL); kneeGrpL.add(kneeL,shinL,shpL,ankleGrpL);
  legGrpL.add(thigL,thpL,kneeGrpL);
  g.add(legGrpL);

  const legGrpR=new THREE.Group(); legGrpR.position.set(.135,.93,0);
  const thigR  = bx(.21,.38,.21,suitM, 0,-.19,0);
  const thpR   = bx(.12,.16,.10,armorM,-.10,-.18,.06);
  const kneeGrpR=new THREE.Group(); kneeGrpR.position.set(0,-.38,0);
  const kneeR  = bx(.22,.13,.14,plateM, 0,-.01,.05);
  const shinR  = bx(.17,.35,.17,suitM,  0,-.19,0);
  const shpR   = bx(.09,.12,.05,armorM,  .09,-.16,.10);
  const ankleGrpR=new THREE.Group(); ankleGrpR.position.set(0,-.35,0);
  const bootR  = bx(.21,.15,.28,bootM,  0,-.07,.025);
  ankleGrpR.add(bootR); kneeGrpR.add(kneeR,shinR,shpR,ankleGrpR);
  legGrpR.add(thigR,thpR,kneeGrpR);
  g.add(legGrpR);

  g.limbs={ torso:torsoGrp, armL:armGrpL, armR:armGrpR, elbowL:elbowGrpL, elbowR:elbowGrpR, legL:legGrpL, legR:legGrpR, kneeL:kneeGrpL, kneeR:kneeGrpR, head:headGrp };

  g.visible=false;
  sc.add(g);
  return g;
})();
let tpvWalkPhase=0;

// TPV camera offset constants
const TPV_DIST=3.2, TPV_HEIGHT=1.4, TPV_SIDE=0.3;

function toggleTpv(){
  G.tpv=!G.tpv;
  document.getElementById('tpv-ind').classList.toggle('on',G.tpv);

  if(wm) wm.visible=!G.tpv;

  document.getElementById('xh').style.opacity=G.tpv?'0':'1';
  document.getElementById('fs-dot').style.opacity='0';
  const btn=document.getElementById('pu-tpv-btn');
  if(btn) btn.style.borderColor=G.tpv?'#00c4ff':'';
}

let lt=0, en=[];
function loop(ts){
  requestAnimationFrame(loop);
  const dt=Math.min((ts-lt)/1000,.05); lt=ts;
  if(!G.run||G.pause){ren.render(sc,cam);return;}
  const w=WP[G.wi];
  if((G.keys.Fire&&w.auto)||G.keys.FO){shoot();G.keys.FO=false;}
  if(G.reload){G.rlt-=dt;if(G.rlt<=0)doRel();}
  if(!G.keys.Fire&&!G.keys.FO){const k=S.recoilRecov;shotCount*=Math.exp(-k*dt);if(shotCount<0.05)shotCount=0;}
  document.getElementById('fs-dot').style.opacity=(shotCount<0.5&&!G.keys.Fire)?'1':'0';
  const kickDecay=1.0-Math.min(1,dt*S.kickRecov);
  camKickPitch*=kickDecay; camKickYaw*=kickDecay;
  if(Math.abs(camKickPitch)<0.0001)camKickPitch=0; if(Math.abs(camKickYaw)<0.0001)camKickYaw=0;
  if(S.leanEnabled){G.leanTarget=(G.keys.KeyQ?-1:0)+(G.keys.KeyE?1:0);G.leanTarget=Math.max(-1,Math.min(1,G.leanTarget));}
  else{G.leanTarget=0;}
  G.leanCurrent+=(G.leanTarget-G.leanCurrent)*Math.min(1,dt*S.leanSpeed*1.2);
  move(dt); updRound(dt); en.forEach(e=>e.upd(dt,cam.position));
  const leanRi=new THREE.Vector3(Math.cos(G.yaw),0,-Math.sin(G.yaw));
  const leanOff=leanRi.clone().multiplyScalar(G.leanCurrent*S.leanStrength);
  cam.position.add(leanOff);
  document.getElementById('lean-l').style.opacity=Math.max(0,-G.leanCurrent).toFixed(2);
  document.getElementById('lean-r').style.opacity=Math.max(0,G.leanCurrent).toFixed(2);
  for(let i=fls.length-1;i>=0;i--){fls[i].t-=dt;if(fls[i].t<=0){sc.remove(fls[i].l);fls.splice(i,1);}else fls[i].l.intensity=8*(fls[i].t/.07);}
  for(let i=pts.length-1;i>=0;i--){const p=pts[i];p.t-=dt;p.m.position.addScaledVector(p.v,dt);

    const isSmoke=p.m.geometry&&p.m.geometry.parameters&&p.m.geometry.parameters.radius>0.15;
    const gravity=isSmoke?-1.5:-10;
    p.v.y+=gravity*dt;
    if(isSmoke){p.m.scale.addScalar(dt*.8); p.v.x*=Math.pow(.92,dt*60); p.v.z*=Math.pow(.92,dt*60);}
    const life=isSmoke?1.5:.45;
    p.m.material.opacity=Math.max(0,p.t/life*(isSmoke?.6:1));
    p.m.material.transparent=true;
    if(p.t<=0){sc.remove(p.m);pts.splice(i,1);}}
  for(let i=grs.length-1;i>=0;i--){const g=grs[i];g.t-=dt;g.v.y-=16*dt;g.m.position.addScaledVector(g.v,dt);g.m.rotation.x+=dt*6;if((g.m.position.y<.1||g.t<=0)&&!g.done){g.done=true;explode(g.m.position.clone());sc.remove(g.m);grs.splice(i,1);}}
  for(let i=bloods.length-1;i>=0;i--){const b=bloods[i];b.t-=dt;if(b.pool){b.m.material.opacity=Math.max(0,b.t/b.life*.85);if(b.t<=0){sc.remove(b.m);bloods.splice(i,1);}}else{b.m.position.addScaledVector(b.v,dt);b.v.y-=14*dt;if(b.m.position.y<.02){b.m.position.y=.02;b.v.multiplyScalar(.12);}b.m.material.opacity=Math.max(0,b.t/b.life);if(b.t<=0){sc.remove(b.m);bloods.splice(i,1);}}}
  updFlicker(dt);

  sc.children.forEach(c=>{if(c.userData&&c.userData.isSnow){const pos=c.geometry.attributes.position;const arr=pos.array;for(let i=0;i<arr.length;i+=3){arr[i]  =(arr[i]  + dt*0.8 + 44)%88-44;arr[i+1]=(arr[i+1]-dt*1.2+7)%7;arr[i+2]=(arr[i+2]+dt*0.3+32)%64-32;}pos.needsUpdate=true;}});

  for(let i=shockwaves.length-1;i>=0;i--){
    const sw=shockwaves[i]; sw.t+=dt;
    const prog=sw.t/sw.dur;
    if(prog>=1){sc.remove(sw.m);shockwaves.splice(i,1);continue;}
    const eased=1-Math.pow(1-prog,2);
    const newR=sw.maxR*eased;
    sw.m.scale.set(newR/0.2,1,newR/0.2);
    sw.m.material.opacity=0.9*(1-prog);
  }
  drawMM();

  if(G.tpv && !G.pause){

    const eyeH = G.keys.KeyC ? 1.1 : 1.7;
    const playerFoot = cam.position.clone().sub(new THREE.Vector3(0, eyeH, 0));
    const isMoving = G.keys.KeyW||G.keys.KeyS||G.keys.KeyA||G.keys.KeyD;
    const isSprint = isMoving && G.keys.ShiftLeft;

    if(isMoving) tpvWalkPhase += dt*(isSprint?9:6); else tpvWalkPhase*=.85;
    const wph = tpvWalkPhase;

    playerMesh.visible = true;
    playerMesh.position.copy(playerFoot);
    playerMesh.rotation.y = G.yaw + Math.PI;

    const L = playerMesh.limbs;
    const stride = Math.sin(wph) * 0.32;
    const kneeBend = Math.max(0, stride) * 0.45;
    const kneeStr  = Math.max(0,-stride) * 0.45;

    if(L){
      L.legL.rotation.x = stride;
      L.legR.rotation.x = -stride;

      L.kneeL.rotation.x = Math.abs(stride)*0.4 + (isSprint?0.15:0.08);
      L.kneeR.rotation.x = Math.abs(stride)*0.4 + (isSprint?0.15:0.08);

      L.armL.rotation.x = -stride * 0.55;
      L.armR.rotation.x =  stride * 0.55;

      L.elbowL.rotation.x = 0.15 + Math.abs(stride)*0.2;
      L.elbowR.rotation.x = 0.15 + Math.abs(stride)*0.2;

      L.torso.rotation.y = stride * 0.08;

      L.head.rotation.x = G.pitch * 0.3;
    }

    const torBob = Math.abs(Math.sin(wph))*0.045;
    playerMesh.position.y = playerFoot.y - torBob;

    const origPos = cam.position.clone();
    const origRotX = cam.rotation.x, origRotY = cam.rotation.y, origRotZ = cam.rotation.z;
    const bxDir = Math.sin(G.yaw), bzDir = Math.cos(G.yaw);
    const sx = Math.cos(G.yaw) * TPV_SIDE, sz = -Math.sin(G.yaw) * TPV_SIDE;
    const tpvPos = origPos.clone().add(new THREE.Vector3(
      bxDir * TPV_DIST + sx,
      TPV_HEIGHT,
      bzDir * TPV_DIST + sz
    ));
    cam.position.copy(tpvPos);
    const lookTarget = origPos.clone().add(new THREE.Vector3(0, 0.3, 0));
    cam.lookAt(lookTarget);
    if(wm) wm.visible = false;
    ren.render(sc, cam);

    cam.position.copy(origPos);
    cam.rotation.set(origRotX, origRotY, origRotZ, 'YXZ');
    if(wm) wm.visible = false;
    playerMesh.visible = false;
  } else {
    playerMesh.visible = false;
    ren.render(sc, cam);
  }
  cam.position.sub(leanOff);
}

