document.getElementById("sb2").addEventListener("click",()=>{
  applySettings();
  const diff=DIFF_DEF[selectedDiffId];
  S.enemyCount=diff.enemyCount; S.aiK=diff.aiK; S.enemyFR=diff.enemyFR;
  S.startMoney=diff.startMoney; S.killReward=diff.killReward;
  G.diffMult=diff.dmgMult;
  G.hp=diff.playerHP; G.armor=S.armorStart;
  G.money=diff.startMoney; G.lossStreak=0; G.inBuyPhase=false;
  G.onGround=true; G.vel=new THREE.Vector3();
  G.kills=0; G.ps=0; G.es=0; G.round=1;
  G.attachments=defaultAttachments();
  shotCount=0; camKickPitch=0; camKickYaw=0; wBob=0; wKick=0;

  const BASE_WP=[
    {name:"ARC-15",      slot:1, dmg:22, rof:700, mag:30,  res:90,  rl:2.2, auto:true,  rng:200, penMult:0.45, price:2700},
    {name:"GHOST G17",   slot:2, dmg:28, rof:400, mag:17,  res:51,  rl:1.4, auto:false, rng:80,  penMult:0.25, price:500},
    {name:"COMBAT KNIFE",slot:3, dmg:90, rof:120, mag:1,   res:999, rl:0.1, auto:false, rng:3,   penMult:0,    price:0,   melee:true},
    {name:"FRAG",        slot:4, dmg:95, rof:60,  mag:2,   res:4,   rl:0.5, auto:false, rng:20,  penMult:0,    price:300, gren:true},
    {name:"SRX-50",      slot:5, dmg:70, rof:45,  mag:5,   res:15,  rl:3.2, auto:false, rng:300, penMult:0.72, price:4750},
  ];
  const primSC=SHOP_CATALOG.find(w=>w.id===G_LOADOUT.primary);
  const secSC=SHOP_CATALOG.find(w=>w.id===G_LOADOUT.secondary);
  WP[0]=Object.assign({},primSC?WP[primSC.wpIdx]:BASE_WP[0]);
  WP[1]=Object.assign({},secSC?WP[secSC.wpIdx]:BASE_WP[1]);
  WP[2]=Object.assign({},BASE_WP[2]); WP[3]=Object.assign({},BASE_WP[3]); WP[4]=Object.assign({},BASE_WP[4]);
  G.ammo=WP.slice(0,5).map((w,i)=>({c:getEffectiveMag(i),r:w.res}));

  bloods.forEach(b=>sc.remove(b.m)); bloods.length=0;
  updMoney();

  const ef=document.getElementById('ov-enter-flash');
  if(ef){
    ef.style.transition='opacity .08s'; ef.style.opacity='1';
    setTimeout(()=>{
      ef.style.transition='opacity .4s'; ef.style.opacity='0';
    },120);
  }
  document.getElementById("ov").style.display="none";
  document.getElementById("hud").style.display="block";
  buildMap(selectedMapId);
  mkWep(WP[0]); sc.add(cam);
  en.forEach(e=>sc.remove(e.mesh)); en=[];
  for(let i=0;i<S.enemyCount;i++)en.push(new Enemy(i));
  updHp(); updAm(); updAttachUI();
  G.run=true; G.ron=true; rtm=75;
  document.body.classList.add('playing');
  cam.position.set(0,1.7,0);
  document.getElementById("rn").textContent="1";
  document.getElementById("kn").textContent="0";
  document.getElementById("kf").innerHTML="";
  ren.domElement.requestPointerLock();
  requestAnimationFrame(ts=>{lt=ts;loop(ts);});
});

window.addEventListener("resize",()=>{cam.aspect=innerWidth/innerHeight;cam.updateProjectionMatrix();ren.setSize(innerWidth,innerHeight);});
